const COLORS = {
  primary: '#E0242A',       // Netro Red
  primaryDark: '#B01C21',   // Darker Red for hover
  dark: '#121417',          // Charcoal Black
  light: '#F8F9FB',         // Soft White
  white: '#FFFFFF',
  text: '#121417',
  textMuted: '#525C67',
  border: '#E2E8F0',
};

// --- COMPONENTS ---

const TopBar = () => (
  <div style={{
    backgroundColor: COLORS.dark,
    color: 'rgba(255,255,255,0.7)',
    fontSize: '0.75rem',
    padding: '10px 5%',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    fontWeight: 400,
    letterSpacing: '0.02em'
  }}>
    <div style={{ display: 'flex', gap: '24px' }}>
      <span style={{ color: 'white', fontWeight: 600 }}>Personal</span>
      <span style={{ cursor: 'pointer' }}>Business</span>
      <span style={{ cursor: 'pointer' }}>Corporate</span>
      <span style={{ cursor: 'pointer' }}>About Us</span>
    </div>
    <div style={{ display: 'flex', gap: '24px' }}>
      <span style={{ cursor: 'pointer' }}>Contact</span>
      <span style={{ cursor: 'pointer' }}>Locate Branch</span>
    </div>
  </div>
);

const Header = ({ onMenuOpen }: { onMenuOpen: () => void }) => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <header style={{
      backgroundColor: COLORS.white,
      height: '85px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      padding: '0 5%',
      boxShadow: scrolled ? '0 10px 30px rgba(0,0,0,0.05)' : 'none',
      borderBottom: scrolled ? 'none' : `1px solid ${COLORS.border}`,
      position: 'sticky',
      top: 0,
      zIndex: 1000,
      transition: 'all 0.3s ease'
    }}>
      <Link to="/" style={{ display: 'flex', alignItems: 'center', textDecoration: 'none' }}>
        <div style={{
          width: '38px',
          height: '38px',
          backgroundColor: COLORS.primary,
          borderRadius: '4px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'white',
          fontWeight: '900',
          fontSize: '22px',
          boxShadow: '0 4px 10px rgba(224, 36, 42, 0.2)'
        }}>N</div>
        <span style={{
          fontSize: '24px',
          fontWeight: '800',
          color: COLORS.dark,
          marginLeft: '12px',
          letterSpacing: '-1px'
        }}>NetroBank</span>
      </Link>

      <nav style={{ display: 'none', gap: '30px', alignItems: 'center' }} className="desktop-nav">
        {['Accounts', 'Cards', 'Loans', 'Investments', 'Insurance'].map(item => (
          <Link key={item} to="#" style={{
            textDecoration: 'none',
            color: COLORS.text,
            fontWeight: '600',
            fontSize: '0.95rem',
            position: 'relative'
          }} className="nav-link">
            {item}
          </Link>
        ))}
        <Link to="#" style={{
          backgroundColor: COLORS.primary,
          color: COLORS.white,
          padding: '12px 28px',
          borderRadius: '6px',
          fontWeight: '700',
          fontSize: '0.9rem',
          textDecoration: 'none',
          marginLeft: '15px',
          transition: 'background-color 0.2s'
        }} onMouseOver={e => e.currentTarget.style.backgroundColor = COLORS.primaryDark}
           onMouseOut={e => e.currentTarget.style.backgroundColor = COLORS.primary}>
          Online Banking
        </Link>
      </nav>

      <button onClick={onMenuOpen} style={{
        display: 'block',
        background: 'none',
        border: 'none',
        cursor: 'pointer',
        padding: '8px'
      }} className="mobile-toggle">
        <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke={COLORS.dark} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
          <line x1="3" y1="12" x2="21" y2="12"></line>
          <line x1="3" y1="6" x2="21" y2="6"></line>
          <line x1="3" y1="18" x2="21" y2="18"></line>
        </svg>
      </button>

      <style>{`
        @media (min-width: 1024px) {
          .desktop-nav { display: flex !important; }
          .mobile-toggle { display: none !important; }
        }
        .nav-link:after {
          content: '';
          position: absolute;
          bottom: -5px;
          left: 0;
          width: 0;
          height: 2px;
          background: ${COLORS.primary};
          transition: width 0.3s;
        }
        .nav-link:hover:after {
          width: 100%;
        }
      `}</style>
    </header>
  );
};

