const App = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  return (
    <HashRouter>
      <div style={{ 
        fontFamily: "'Inter', 'Poppins', sans-serif", 
        color: COLORS.text, 
        backgroundColor: COLORS.light,
        minHeight: '100vh'
      }}>
        <TopBar />
        <Header onMenuOpen={() => setIsMenuOpen(true)} />
        <MobileMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} />

        <Routes>
          <Route path="/" element={
            <>
              <Hero />
              <QuickActions />
              <Features />
              <section style={{ padding: '100px 5%', textAlign: 'center', backgroundColor: COLORS.white }}>
                <div style={{ maxWidth: '800px', margin: '0 auto' }}>
                  <h2 style={{ fontSize: '2.5rem', fontWeight: '800', marginBottom: '20px' }}>Your financial future begins here.</h2>
                  <p style={{ color: COLORS.textMuted, fontSize: '1.2rem', marginBottom: '40px' }}>Join millions who trust NetroBank for their personal and business needs.</p>
                  <Link to="#" style={{
                    backgroundColor: COLORS.dark,
                    color: 'white',
                    padding: '18px 50px',
                    borderRadius: '8px',
                    fontSize: '1.1rem',
                    fontWeight: '700',
                    textDecoration: 'none',
                    display: 'inline-block'
