const Header = ({ onMenuOpen }: { onMenuOpen: () => void }) => {
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <header style={{
      backgroundColor: COLORS.white,
      height: scrolled ? '70px' : '85px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      padding: '0 5%',
      boxShadow: scrolled ? '0 10px 30px rgba(0,0,0,0.05)' : 'none',
      borderBottom: scrolled ? 'none' : `1px solid ${COLORS.border}`,
      position: 'sticky',
      top: 0,
      zIndex: 1000,
      transition: 'all 0.25s cubic-bezier(0.4, 0, 0.2, 1)'
    }}>
      <Link to="/" style={{ display: 'flex', alignItems: 'center', textDecoration: 'none' }}>
        <div style={{
          width: '36px',
          height: '36px',
          backgroundColor: COLORS.primary,
          borderRadius: '4px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'white',
          fontWeight: '800',
          fontSize: '20px',
        }}>N</div>
        <span style={{
          fontSize: '24px',
          fontWeight: 700,
          color: COLORS.dark,
          marginLeft: '12px',
          letterSpacing: '-1px'
        }}>NetroBank</span>
      </Link>

      <nav style={{ display: 'none', gap: '30px', alignItems: 'center' }} className="desktop-nav">
        {['Accounts', 'Cards', 'Loans', 'Investments'].map(item => (
          <Link key={item} to="#" style={{
            textDecoration: 'none',
            color: COLORS.text,
            fontWeight: 600,
            fontSize: '15px',
            position: 'relative',
            transition: `color ${ANIMATION.fast}`
          }} className="nav-link">
            {item}
          </Link>
        ))}
        <Link to="/dashboard" style={{
          textDecoration: 'none',
          color: location.pathname === '/dashboard' ? COLORS.primary : COLORS.text,
          fontWeight: 700,
          fontSize: '15px',
          marginLeft: '10px',
          transition: `color ${ANIMATION.fast}`
        }}>Dashboard</Link>
        <Link to="#" className="primary-btn-hover" style={{
          ...PRIMARY_BUTTON_STYLE,
          marginLeft: '15px',
          fontSize: '14px',
          padding: '12px 20px',
        }}>
          Online Banking
        </Link>
      </nav>

      <button onClick={onMenuOpen} style={{
        display: 'block',
        background: 'none',
        border: 'none',
        cursor: 'pointer',
        padding: '8px',
        transition: `transform ${ANIMATION.fast}`
      }} className="mobile-toggle" onMouseDown={e => e.currentTarget.style.transform = 'scale(0.95)'} onMouseUp={e => e.currentTarget.style.transform = 'scale(1)'}>
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={COLORS.dark} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <line x1="3" y1="12" x2="21" y2="12"></line>
          <line x1="3" y1="6" x2="21" y2="6"></line>
          <line x1="3" y1="18" x2="21" y2="18"></line>
        </svg>
      </button>

      <style>{`
        @media (min-width: 1024px) {
          .desktop-nav { display: flex !important; }
          .mobile-toggle { display: none !important; }
        }
        .nav-link:after {
          content: '';
          position: absolute;
          bottom: -5px;
          left: 0;
          width: 0;
          height: 2px;
          background: ${COLORS.primary};
          transition: width ${ANIMATION.fast};
        }
        .nav-link:hover:after {
          width: 100%;
        }
        .primary-btn-hover:hover {
          background-color: ${COLORS.primaryHover} !important;
          transform: translateY(-1px);
          box-shadow: 0 4px 12px rgba(224, 36, 42, 0.2);
        }
        .primary-btn-hover:active {
          transform: translateY(0);
        }
      `}</style>
    </header>
  );
};

